+    fn fault_injector_reset_clears_rules_and_log() {
+        let cx = Cx::for_testing();
+        let mem = MemoryByteDevice::new(4096 * 4);
+        let dev = ByteBlockDevice::new(mem, 4096).expect("device");
+        let fi = FaultInjector::new(dev, 42);
